import{_ as i,o as s,c as e,a2 as n}from"./chunks/framework.C24VBsJ9.js";const u=JSON.parse('{"title":"主线内核与 imx 内核的差异对比","description":"","frontmatter":{},"headers":[],"relativePath":"tutorial/driver/02_pinctrl_gpio/09_kernel_comparison.md","filePath":"tutorial/driver/02_pinctrl_gpio/09_kernel_comparison.md","lastUpdated":1778600138000}'),l={name:"tutorial/driver/02_pinctrl_gpio/09_kernel_comparison.md"};function t(r,a,p,o,d,c){return s(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="主线内核与-imx-内核的差异对比" tabindex="-1">主线内核与 imx 内核的差异对比 <a class="header-anchor" href="#主线内核与-imx-内核的差异对比" aria-label="Permalink to &quot;主线内核与 imx 内核的差异对比&quot;">​</a></h1><h2 id="前言-为什么要对比两个内核" tabindex="-1">前言：为什么要对比两个内核 <a class="header-anchor" href="#前言-为什么要对比两个内核" aria-label="Permalink to &quot;前言：为什么要对比两个内核&quot;">​</a></h2><p>我们在整个教程中一直提到两个内核：主线内核（third_party/linux_mainline）和 NXP imx 内核（third_party/linux-imx）。你可能会问：为什么需要两个内核？它们有什么区别？</p><p>这一章我们来对比这两个内核在 pinctrl 和 GPIO 子系统上的差异，看看这些差异对我们有什么影响。</p><h2 id="两个内核的定位" tabindex="-1">两个内核的定位 <a class="header-anchor" href="#两个内核的定位" aria-label="Permalink to &quot;两个内核的定位&quot;">​</a></h2><h3 id="主线内核-mainline" tabindex="-1">主线内核（Mainline） <a class="header-anchor" href="#主线内核-mainline" aria-label="Permalink to &quot;主线内核（Mainline）&quot;">​</a></h3><p>主线内核是 Linux 官方发布的内核，由 Linus Torvalds 和维护者社区管理。它的特点是：</p><ul><li><strong>通用性强</strong>：支持各种架构和各种厂商的芯片</li><li><strong>更新快</strong>：每 2-3 个月发布一个大版本</li><li><strong>质量高</strong>：经过严格的代码审查和测试</li><li><strong>文档完整</strong>：有完整的设备树绑定文档</li></ul><p>对于 i.MX 6ULL，主线内核的 pinctrl 和 GPIO 驱动位于：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>drivers/pinctrl/freescale/pinctrl-imx.c</span></span>
<span class="line"><span>drivers/gpio/gpio-mxc.c</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="nxp-imx-内核" tabindex="-1">NXP imx 内核 <a class="header-anchor" href="#nxp-imx-内核" aria-label="Permalink to &quot;NXP imx 内核&quot;">​</a></h3><p>NXP imx 内核是 NXP 公司维护的内核，基于主线内核，但添加了 NXP 特有的功能和支持。它的特点是：</p><ul><li><strong>芯片特定</strong>：专注于 NXP i.MX 系列芯片</li><li><strong>功能更全</strong>：可能包含一些主线内核还没有的功能</li><li><strong>更新慢</strong>：跟随主线内核，但有延迟</li><li><strong>私有补丁</strong>：可能包含一些 NXP 私有的补丁</li></ul><h2 id="pinctrl-子系统差异" tabindex="-1">Pinctrl 子系统差异 <a class="header-anchor" href="#pinctrl-子系统差异" aria-label="Permalink to &quot;Pinctrl 子系统差异&quot;">​</a></h2><h3 id="代码量对比" tabindex="-1">代码量对比 <a class="header-anchor" href="#代码量对比" aria-label="Permalink to &quot;代码量对比&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>主线内核 pinctrl-imx.c:  21982 字节</span></span>
<span class="line"><span>imx 内核 pinctrl-imx.c:   21982 字节</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>文件大小完全一样，说明核心实现是同步的。</p><h3 id="api-差异" tabindex="-1">API 差异 <a class="header-anchor" href="#api-差异" aria-label="Permalink to &quot;API 差异&quot;">​</a></h3><p>两个内核的 pinctrl API 完全兼容。核心数据结构和函数签名都是一样的。</p><p>主要的差异可能在于：</p><ol><li><p><strong>SCU 支持</strong>：imx 内核对 SCU（System Controller Unit）的支持可能更完善。SCU 是某些 i.MX 芯片特有的功能，用于管理芯片级的资源。</p></li><li><p><strong>错误处理</strong>：主线内核可能有更严格的错误检查。</p></li></ol><h3 id="设备树绑定差异" tabindex="-1">设备树绑定差异 <a class="header-anchor" href="#设备树绑定差异" aria-label="Permalink to &quot;设备树绑定差异&quot;">​</a></h3><p>主线内核的设备树绑定文档正在从 <code>.txt</code> 格式迁移到 <code>.yaml</code> 格式：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>主线内核：Documentation/devicetree/bindings/pinctrl/fsl,imx-pinctrl.yaml</span></span>
<span class="line"><span>imx 内核： Documentation/devicetree/bindings/pinctrl/fsl,imx-pinctrl.txt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><code>.yaml</code> 格式的好处是可以用工具验证设备树的正确性，而 <code>.txt</code> 格式只能人工检查。</p><h3 id="芯片支持差异" tabindex="-1">芯片支持差异 <a class="header-anchor" href="#芯片支持差异" aria-label="Permalink to &quot;芯片支持差异&quot;">​</a></h3><p>两个内核支持的芯片列表可能略有不同。主线内核倾向于支持所有芯片，而 imx 内核专注于 NXP 的芯片。</p><p>查看支持的芯片：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 主线内核</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;fsl,imx&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> drivers/pinctrl/freescale/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compatible</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># imx 内核</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;fsl,imx&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> drivers/pinctrl/freescale/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compatible</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="gpio-子系统差异" tabindex="-1">GPIO 子系统差异 <a class="header-anchor" href="#gpio-子系统差异" aria-label="Permalink to &quot;GPIO 子系统差异&quot;">​</a></h2><h3 id="代码量对比-1" tabindex="-1">代码量对比 <a class="header-anchor" href="#代码量对比-1" aria-label="Permalink to &quot;代码量对比&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>主线内核 gpio-mxc.c:  733 行</span></span>
<span class="line"><span>imx 内核 gpio-mxc.c:   739 行</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>只差 6 行，说明 GPIO 驱动已经相当稳定了。</p><h3 id="api-差异-1" tabindex="-1">API 差异 <a class="header-anchor" href="#api-差异-1" aria-label="Permalink to &quot;API 差异&quot;">​</a></h3><p>两个内核的 GPIO API 完全兼容。<code>of_get_named_gpio</code>、<code>gpio_direction_output</code>、<code>gpio_set_value</code> 这些函数在两个内核中的行为是一致的。</p><h3 id="设备树绑定差异-1" tabindex="-1">设备树绑定差异 <a class="header-anchor" href="#设备树绑定差异-1" aria-label="Permalink to &quot;设备树绑定差异&quot;">​</a></h3><p>和 pinctrl 类似，主线内核的设备树绑定文档是 <code>.yaml</code> 格式，而 imx 内核是 <code>.txt</code> 格式：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>主线内核：Documentation/devicetree/bindings/gpio/fsl-imx-gpio.yaml</span></span>
<span class="line"><span>imx 内核： Documentation/devicetree/bindings/gpio/fsl-imx-gpio.txt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="实际影响" tabindex="-1">实际影响 <a class="header-anchor" href="#实际影响" aria-label="Permalink to &quot;实际影响&quot;">​</a></h2><h3 id="对驱动开发的影响" tabindex="-1">对驱动开发的影响 <a class="header-anchor" href="#对驱动开发的影响" aria-label="Permalink to &quot;对驱动开发的影响&quot;">​</a></h3><p>好消息是：对于大多数驱动开发者来说，这两个内核的差异可以忽略。你的驱动代码在两个内核上都能正常工作。</p><p>需要注意的是：</p><ol><li><strong>设备树格式</strong>：如果你参考主线内核的文档，要注意设备树绑定可能已经是 <code>.yaml</code> 格式了。</li><li><strong>SCU 功能</strong>：如果你的芯片需要使用 SCU 功能，可能需要使用 imx 内核。</li><li><strong>私有补丁</strong>：NXP 可能有一些私有补丁，只在 imx 内核中存在。</li></ol><h3 id="对移植的影响" tabindex="-1">对移植的影响 <a class="header-anchor" href="#对移植的影响" aria-label="Permalink to &quot;对移植的影响&quot;">​</a></h3><p>如果你需要从 imx 内核迁移到主线内核（或反之），需要注意：</p><ol><li><strong>检查设备树兼容性</strong>：确保设备树中的 compatible 字符串在目标内核中存在。</li><li><strong>检查驱动支持</strong>：确保目标内核中有你需要的驱动。</li><li><strong>测试功能</strong>：特别要测试那些 NXP 特有的功能。</li></ol><h2 id="选择建议" tabindex="-1">选择建议 <a class="header-anchor" href="#选择建议" aria-label="Permalink to &quot;选择建议&quot;">​</a></h2><h3 id="什么时候用主线内核" tabindex="-1">什么时候用主线内核 <a class="header-anchor" href="#什么时候用主线内核" aria-label="Permalink to &quot;什么时候用主线内核&quot;">​</a></h3><ul><li>你需要最新的内核特性</li><li>你需要最稳定的质量保证</li><li>你的应用不需要 NXP 特有的功能</li><li>你希望代码更容易 upstream</li></ul><h3 id="什么时候用-imx-内核" tabindex="-1">什么时候用 imx 内核 <a class="header-anchor" href="#什么时候用-imx-内核" aria-label="Permalink to &quot;什么时候用 imx 内核&quot;">​</a></h3><ul><li>你需要使用 NXP 特有的功能（如 SCU）</li><li>你需要 NXP 的技术支持</li><li>你的应用已经在 imx 内核上验证过</li><li>你需要使用 NXP 的私有补丁</li></ul><h2 id="未来趋势" tabindex="-1">未来趋势 <a class="header-anchor" href="#未来趋势" aria-label="Permalink to &quot;未来趋势&quot;">​</a></h2><p>主线内核和 imx 内核的差异正在逐渐缩小。NXP 正在努力把更多功能 upstream 到主线内核，而主线内核也在不断增强对 ARM 嵌入式的支持。</p><p>长期来看，主线内核会是更好的选择，因为它有更大的社区支持、更快的更新速度、更严格的质量控制。</p><p>但短期内，对于一些 NXP 特有的功能，你可能还是需要使用 imx 内核。</p><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><p>两个内核在 pinctrl 和 GPIO 子系统上的差异很小，主要是在一些边缘功能和文档格式上。</p><p>对于我们的 LED 驱动来说，两个内核完全兼容。你可以用同一份代码、同一个设备树，在两个内核上都能正常工作。</p><p>说实话，内核选择是一个很实际的问题。如果你在做产品开发，建议优先考虑主线内核，因为它的质量更可靠、社区更活跃。如果你在做一些 NXP 特有的功能开发，可能需要使用 imx 内核。</p><hr><p><strong>教程总结</strong></p><p>到这里，我们的 pinctrl + GPIO 教程就结束了。让我们回顾一下我们走过的路：</p><ol><li><strong>第一章</strong>：从寄存器到子系统，理解为什么需要子系统</li><li><strong>第二章</strong>：硬件原理，理解 IOMUXC 和 GPIO 模块是怎么工作的</li><li><strong>第三章</strong>：pinctrl 子系统架构，理解它的核心数据结构和实现</li><li><strong>第四章</strong>：设备树 pinctrl 配置，学会怎么写 pinctrl 配置</li><li><strong>第五章</strong>：GPIO 子系统架构，理解它的分层设计</li><li><strong>第六章</strong>：设备树 GPIO 配置，学会怎么引用 GPIO</li><li><strong>第七章</strong>：完整驱动实现，看真实的驱动代码</li><li><strong>第八章</strong>：编译测试，上板验证</li><li><strong>第九章</strong>：内核对比，了解两个内核的差异</li></ol><p>如果你跟着教程一步步走过来，现在你应该能够：</p><ul><li>理解 pinctrl 和 GPIO 子系统的工作原理</li><li>能够在设备树中正确配置 pinctrl 和 GPIO</li><li>能够编写使用 pinctrl 和 GPIO 子系统的驱动代码</li><li>能够编译、部署和测试驱动</li></ul><p>说实话，pinctrl 和 GPIO 子系统确实是 Linux 驱动开发里非常基础但也非常重要的部分。掌握了这两个子系统，你就掌握了驱动开发的&quot;基本功&quot;。</p><p>继续加油！</p><hr><p><strong>相关阅读</strong></p><ul><li><a href="./../00_chardev_base/01_introduction">字符设备驱动基础</a></li><li><a href="./../01_device_tree_base/01_device_tree_introduction">设备树基础</a></li><li><a href="./../00_chardev_base/08_memory_mapped_io">内存映射 I/O</a></li></ul>`,70)])])}const m=i(l,[["render",t]]);export{u as __pageData,m as default};
